var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"하아앗!","JPN":"はああっ！","ENG":"Haaah!","TWN":"哈啊！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"해치웠나?","JPN":"やったか？","ENG":"Is it dead?","TWN":"解決了嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카가 잠깐 물러난 것일 뿐이래.","JPN":"オルカがちょっとの間後退しただけだって。","ENG":"Orca says she only stepped back for a moment.","TWN":"奧爾卡只是稍微退開而已。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"힘든 상대였어. 미끈거리는 촉수가 잔뜩…….","JPN":"手強い相手だった。ベトベトの触手がいっぱい……","ENG":"It was a tough one. All those slimy tentacles...","TWN":"這次很難纏，一大堆黏糊糊的觸手……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"오르카, 네가 크라켄을 상대하는 동안 우리 쪽도 힘들었다고.","JPN":"オルカ、お前がクラーケンと戦ってる間、こっちも大変だったんだぞ。","ENG":"Orca, while you were handling Kraken, things were rough on our end too.","TWN":"奧爾卡，你在對付克拉肯時我們這邊也很辛苦。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"갑판을 기어오르는 침식체로도 모자라서 육지에서나 보던 녀석들이 바다속에서 튀어 오르다니…….","JPN":"デッキによじ登ってくる侵食体だけじゃなくて、陸地でしか見たことないやつらが海の中から飛び出てきてな……","ENG":"As if the C.O.s crawling up the deck weren't enough, creatures we only see on land started leaping out of the sea...","TWN":"不只是從甲板爬上來的侵蝕體，連平常在陸地才能看到的傢伙都從海裡跳出來……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그만큼 이번 일이 심각하다는 증거겠지.","JPN":"それほど今回の事態が深刻だっていう証拠ね。","ENG":"Which shows how serious this whole situation is.","TWN":"這就代表事態有多嚴重。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이터니움 쉴드량이나 잘 확인해.","JPN":"エタニウムシールドの残量、しっかり確認してよ。","ENG":"Check your Eternium shields.","TWN":"記得確認永恆之金護盾的數量。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"우리 같은 일반인들은 순식간에 높아지는 CSE레벨을 견디기 힘들 테니까.","JPN":"私たちみたいな一般人はあっという間に高くなるCSEレベルに耐えられないんだから。","ENG":"Ordinary people like us can't endure fast-rising CSE levels for long.","TWN":"像我們這種一般人，無法承受CSE等級突然飆升。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"현재 CSE 레벨은 4.2…….","JPN":"現在のCSEレベルは4.2……","ENG":"Current CSE level is 4.2...","TWN":"現在CSE的等級是4.2……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"쉴드가 얼마나 버틸 수 있을지 잘 모르겠네.","JPN":"シールドがどれくらい持つかわからないわね。","ENG":"Not sure how long the shields will last.","TWN":"不確定護盾能撐多久。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"둘은 먼저 돌아가 있어.","JPN":"2人は先に帰ってて。","ENG":"You two should head back first.","TWN":"你們先回去。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카가 앞으로 대균열에 가까워질수록 더 위험해질 거래.","JPN":"オルカが、これから大亀裂に近づくほどもっと危険になるって。","ENG":"Orca says it'll only get more dangerous the closer she gets to the Grand Dimension Crevice.","TWN":"奧爾卡越靠近大峽谷就會越危險。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 오르카. 위험한 건 너희도 마찬가지야.","JPN":"でもオルカ。危険なのはあんたたちも同じじゃない。","ENG":"But Orca, it's just as dangerous for you.","TWN":"但是奧爾卡，你們也很危險啊。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"우리 몸은 우리가 알아서 챙길 테니까, 너희는 크게 다치지 않을 것만 생각하라고.","JPN":"自分の身は自分で守るわ。そっちは怪我をしないことだけ考えて。","ENG":"We'll take care of ourselves. Just focus on not getting seriously hurt.","TWN":"我們自己會顧好我們的身體，你們只要保證別受重傷就好。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"무사히 돌아가면 3일 동안은 마시멜로만 먹게 해줄게.","JPN":"無事帰ったら、3日はマシュマロ食べ放題させてあげるから。","ENG":"Make it back safely and I'll let you eat nothing but marshmallows for three days.","TWN":"安全回來後，我讓你們連續吃3天棉花糖。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오, 오오…! 마시멜로……!","JPN":"お、おお……！　マシュマロ……！","ENG":"O-oh...! Marshmallows...!","TWN":"哦、哦哦……！棉花糖……！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"침식체를 사냥하는 데 있어 방법은 다양하다 들었다마는…….","JPN":"侵食体狩りには様々な手段があるとは聞いてたけど……","ENG":"I've heard there are many ways to hunt a C.O...","TWN":"聽說狩獵侵蝕體的方法有很多種……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"이건 포식자의 사냥법에 가깝구나.","JPN":"これは飽食者の狩り方に近いわね。","ENG":"But this... is closer to a predator's hunt.","TWN":"不過你這根本是掠食者的狩獵法啊。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"흥미로워.","JPN":"興味深いわ。","ENG":"Interesting.","TWN":"真有趣。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"섬에 아직 침식체들이 많아.","JPN":"島にまだ侵食体がいっぱいいる。","ENG":"There are still lots of C.O.s on the island.","TWN":"島上還有很多侵蝕體。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"서둘러야 해……!","JPN":"急がなきゃ……！","ENG":"We need to hurry...!","TWN":"必須加快速度……！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"칫! 끝이 없이 몰려들고 있어!","JPN":"チッ！　きりがねえ！","ENG":"Tch! They just keep coming!","TWN":"可惡！怎麼殺都殺不完！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그래도 저쪽에서 촉수를 처리해 준 덕에 한시름 놓았습니다.","JPN":"でも、あちらで触手をやっつけてくれたおかげで一息つけました。","ENG":"Thanks to someone taking care of the tentacles over there, at least that's one problem gone.","TWN":"好在你們解決那邊的觸手了，我們這邊才稍微鬆了口氣。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이쪽으로 올라온 침식체들은 키이라 님이라면 막을 수 있을 테니까요.","JPN":"こちら側に這い上がってきた侵食体は、キーラ様なら食い止められるでしょうから。","ENG":"And the ones climbing up here, you can handle them, Miss Kiera.","TWN":"琪伊拉應該能擋住登上這邊的侵蝕體。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};